import './navigation-list-styles.css';
import { Link } from "react-router-dom";
import NagivationData from "../../data/nav/navigation";


const NavigationList = () =>
(
    <nav>
        <ul>
        {NagivationData.map((item, index) => {
            return (
                <li title={item.title}>
                    <Link to={item.path}>
                        {item.icon}
                    </Link>
                </li>
            );
        })}
        </ul>
    </nav>
)

export default NavigationList;
